function cardContractListContains(list: readonly string[] | undefined, value: string): boolean {
  return (list || []).indexOf(value) >= 0;
}

export function cardContractCard(type: string | null | undefined): CardTypeSpec | null {
  return CARD_CONTRACT_CARDS[type || ""] || null;
}

export function cardContractCardKeys(): string[] {
  return Object.keys(CARD_CONTRACT_CARDS);
}

export function cardContractCardLabel(type: string | null | undefined): string {
  const card = cardContractCard(type);
  return card ? card.label : (type || "Switch");
}

export function cardContractAllowInSubpage(type: string | null | undefined): boolean {
  const card = cardContractCard(type);
  return !!(card && card.allowInSubpage);
}

export function cardContractPickerKey(type: string | null | undefined): string {
  const card = cardContractCard(type);
  return card && card.pickerKey ? card.pickerKey : "";
}

export function cardContractHidden(type: string | null | undefined): boolean {
  const card = cardContractCard(type);
  return !!(card && card.hidden);
}

export function cardContractOptions(type: string | null | undefined): CardOptionSpec[] {
  const card = cardContractCard(type);
  return card && card.options ? JSON.parse(JSON.stringify(card.options)) as CardOptionSpec[] : [];
}

export function cardContractDefaultConfig(type: string | null | undefined): CardConfig {
  const card = cardContractCard(type);
  const defaults = card && card.default ? card.default : CARD_CONTRACT_CARDS[""]!.default;
  return Object.assign({}, defaults);
}

export function cardContractDomains(type: string | null | undefined): string[] {
  const card = cardContractCard(type);
  return card && card.domains ? card.domains.slice() : [];
}

export function cardContractMigrationAlias(type: string | null | undefined): Partial<CardConfig> | null {
  const alias = CARD_CONTRACT_MIGRATION_ALIASES[type || ""];
  return alias ? Object.assign({}, alias) : null;
}

export function cardContractIsBrightnessSliderType(type: string): boolean {
  return cardContractListContains(CARD_CONTRACT_BRIGHTNESS_SLIDER_TYPES, type);
}

export function cardContractIsFanCardType(type: string | null | undefined): boolean {
  return Object.prototype.hasOwnProperty.call(CARD_CONTRACT_FAN_DEFAULT_ICONS, type || "");
}

export function cardContractFanDefaultIcon(type: string): string {
  return CARD_CONTRACT_FAN_DEFAULT_ICONS[type] || CARD_CONTRACT_FAN_DEFAULT_ICONS.fan_speed || "Fan Speed 2";
}

export function cardContractFanDefaultIconOn(type: string): string {
  return CARD_CONTRACT_FAN_DEFAULT_ICON_ON[type] || "Auto";
}

export function cardContractIsOptionSelectType(type: string): boolean {
  return type === "option_select";
}

export function cardContractIsOptionSelectAction(action: string): boolean {
  return cardContractListContains(CARD_CONTRACT_OPTION_SELECT_ACTIONS, action);
}

export function cardContractSubpageTypeCode(type: string | null | undefined): string {
  return CARD_CONTRACT_SUBPAGE_TYPE_CODES[type || ""] || (type || "");
}

export function cardContractSubpageTypeFromCode(code: string | null | undefined): string {
  return CARD_CONTRACT_SUBPAGE_TYPES_BY_CODE[code || ""] || (code || "");
}

export function cardContractLargeNumbersSupported(type: string | null | undefined, precision: string): boolean {
  const rule = CARD_CONTRACT_LARGE_NUMBERS[type || ""];
  if (rule === true) return true;
  if (!rule) return false;
  if (rule.excludedPrecisions) return !cardContractListContains(rule.excludedPrecisions, precision || "");
  if (rule.precisions) return cardContractListContains(rule.precisions, precision || "");
  return false;
}

export function cardContractOptionName(name: string | null | undefined): string {
  return CARD_CONTRACT_OPTION_NAMES[name || ""] || name || "";
}
